namespace BlazorNotifications.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
    public bool IsRead { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed initial fake data
        _notifications.AddRange(new[]
        {
            new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-30) },
            new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-20) },
            new NotificationItem { Id = _nextId++, Message = "New feature: dark mode is available.", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
        });
    }

    /// <summary>Returns all notifications.</summary>
    public List<NotificationItem> GetNotifications()
    {
        lock (_lock)
        {
            return _notifications.OrderByDescending(n => n.Timestamp).ToList();
        }
    }

    /// <summary>Returns only notifications newer than the given ID.</summary>
    public List<NotificationItem> GetNotificationsSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications
                .Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
        }
    }

    /// <summary>Simulates new notifications arriving over time.</summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "You have a new follower.",
            "Someone commented on your post.",
            "Your export is ready to download.",
            "Scheduled maintenance tonight at 11 PM.",
            "A team member mentioned you.",
        };

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new NotificationItem
            {
                Id = _nextId++,
                Message = msg,
                Timestamp = DateTime.UtcNow,
            });
        }
    }
}

