@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var item in _notifications)
        {
            <li class="list-group-item">
                <strong>@item.Message</strong>
                <small class="text-muted ms-2">@item.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.NotificationItem> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial data during prerender AND on interactive init.
        // This ensures SSR HTML has content; the interactive circuit reuses
        // the same call (no double-fetch since it's a fast in-memory read).
        _notifications = NotificationService.GetNotifications();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires on the interactive circuit, never during
            // static SSR prerender. Safe to start background work here.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5000, ct).ConfigureAwait(false);

            if (ct.IsCancellationRequested)
                break;

            // Simulate a new notification arriving server-side
            NotificationService.SimulateIncoming();

            var newer = NotificationService.GetNotificationsSince(_lastSeenId);
            if (newer.Count > 0)
            {
                _lastSeenId = newer.Max(n => n.Id);
                await InvokeAsync(() =>
                {
                    _notifications.InsertRange(0, newer);
                    StateHasChanged();
                });
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

